<h1 class="h3 mb-3">Email Templates</h1><div class="accordion" id="templates"><?php foreach($templates as $n=>$t):?><div class="accordion-item"><h2 class="accordion-header"><button class="accordion-button <?= $n?'collapsed':'' ?>" data-bs-toggle="collapse" data-bs-target="#t<?=e($t['id'])?>"><?=e($t['name'])?></button></h2><div id="t<?=e($t['id'])?>" class="accordion-collapse collapse <?= !$n?'show':'' ?>"><div class="accordion-body"><form method="post" action="/portal/email-templates/<?=e($t['id'])?>" class="row g-3"><?=csrf_field()?><div class="col-md-4"><label class="form-label">Name</label><input class="form-control" name="name" value="<?=e($t['name'])?>"></div><div class="col-md-8"><label class="form-label">Subject</label><input class="form-control" name="subject" value="<?=e($t['subject'])?>"></div><div class="col-12"><label class="form-label">HTML body</label><textarea class="form-control font-monospace" rows="8" name="html_body"><?=e($t['html_body'])?></textarea></div><div class="col-12"><label class="form-check"><input type="checkbox" class="form-check-input" name="active" <?=checked((bool)$t['active'])?>> Active</label><button class="btn btn-primary mt-2">Save template</button></div></form></div></div></div><?php endforeach;?></div>
